 80→          }
 81→          resolve();
 82→        });
 83→      });
 84→
 85→      try {
 86→        const handler = getMCPHandlerInstance();
 87→        handler?.shutdown();
 88→      } catch (error) {
 89→        logger.error('Error shutting down MCP handler', error);
 90→      }
 91→
 92→      try {
 93→        await redisClient.disconnect();
 94→      } catch (error) {
 95→        logger.error('Error closing Redis connection during shutdown', error);
 96→      }
 97→
 98→      clearTimeout(forceExitTimer);
 99→      logger.info('Graceful shutdown complete');
100→      process.exit(0);

