128→  memoryPressure.set(heapPercent);
129→
130→  // Check for critical memory pressure
131→  if (heapPercent > 90) {
132→    logger.error('⚠️  CRITICAL memory pressure detected', {
133→      tool: toolName,
134→      heapPercent: heapPercent.toFixed(1),
135→      heapUsedMB: (memBefore.heapUsed / 1024 / 1024).toFixed(1),
136→      heapTotalMB: (memBefore.heapTotal / 1024 / 1024).toFixed(1),
137→      sessionId: context.sessionId
138→    });
139→  }
140→
141→  // Extract tool domain from name (e.g., "app" from "mittwald_app_list")
142→  const toolDomain = toolName.includes('_') ? toolName.split('_')[1] : 'unknown';
143→  const sessionId = context.sessionId || `session-${Date.now()}`;
144→
145→  // Log tool call start (debug level - high frequency)
146→  structuredLogger.debug({
147→    event: 'tool_call_start',
148→    toolName,
149→    toolDomain,
150→    sessionId,
151→    input: {
152→      arguments: sanitizeValue(request.params.arguments),
153→    },
154→  }, 'Tool call initiated');
155→
156→  try {
157→    // Ensure tools are loaded
158→    await ensureToolsInitialized();
159→    
160→    logger.info(`🔧 handleToolCall called for tool: ${request.params.name}`);
161→    
162→    // Create minimal context for tool handlers
163→    const handlerContext: ToolHandlerContext = {
164→      userId: 'cli-user',
165→      sessionId: context.sessionId,
166→      progressToken: request.params._meta?.progressToken,
167→    };
168→
169→    // Validate arguments are provided
170→    if (!request.params.arguments) {
171→      const toolName = request.params?.name || 'unknown';
172→      logger.error("Tool call missing required arguments", { toolName });
173→      
174→      // Provide helpful error message for specific tools
175→      if (toolName === 'mittwald_domain_virtualhost_create') {
176→        throw new Error("Arguments are required. Expected: { hostname: string, pathToApp?: string[], pathToUrl?: string[], pathToContainer?: string[] }. At least one path mapping is required. For containers use pathToContainer: ['/:c-xxxxx:port/tcp'].");
177→      }
178→      
179→      throw new Error(`Arguments are required for tool '${toolName}'`);
180→    }
181→
182→    // Check if tool is explicitly excluded (disabled for safety)
183→    if (isToolExcluded(request.params.name)) {
184→      const reason = getExclusionReason(request.params.name);
185→      logger.warn(`Attempted to call disabled tool: ${request.params.name}`, {
186→        toolName: request.params.name,
187→        reason: reason || 'excluded_for_safety'
188→      });
189→
190→      toolCallsTotal.inc({ tool_name: toolName, status: 'disabled' });
191→      end(); // Record duration
192→
193→      return {
194→        content: [
195→          {
196→            type: 'text',
197→            text: JSON.stringify({
198→              status: 'error',
199→              message: `Tool '${request.params.name}' is disabled for safety reasons: ${reason || 'security policy'}.`,
200→              data: {
201→                toolName: request.params.name,
202→                reason: 'excluded_for_safety',
203→                suggestedAction: 'Please verify this action is necessary and contact support if required.'
204→              }
205→            }, null, 2),
206→          },
207→        ],
208→        isError: true,
209→      };
210→    }
211→
212→    // Check if tool exists
213→    const tool = TOOLS.find((t) => t.name === request.params.name);
214→    if (!tool) {
215→      logger.error("Unknown tool requested", { toolName: request.params.name });
216→      throw new Error(`${TOOL_ERROR_MESSAGES.UNKNOWN_TOOL} ${request.params.name}`);
217→    }
